mapper.select:
SELECT m_motorcycle.moto_no, m_motorcycle.moto_name, m_motorcycle.seat_height, m_motorcycle.cylinder, m_motorcycle.cooling, m_motorcycle.price, m_motorcycle.comment, m_motorcycle.brand_id, m_motorcycle.version, m_motorcycle.ins_dt, m_motorcycle.upd_dt, m_brand.brand_name FROM m_motorcycle LEFT OUTER JOIN m_brand ON m_motorcycle.brand_id = m_brand.brand_id
m_motorcycle.brand_id = #{brandId}
AND m_motorcycle.moto_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY moto_no;
